'use client';

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { useEffect, useMemo, useState } from 'react';
import type { TimelineMode, TimelineZoom } from '@/domain/types';
import { api } from '@/ui/api/client';
import { ItemList } from '@/ui/components/item-list';
import { useItemActions } from '@/ui/hooks/use-item-actions';
import { queryKeys } from '@/ui/query/keys';
import { useUiStore } from '@/ui/state/ui-store';

type TimelinePageClientProps = {
  initialZoom?: TimelineZoom;
  initialMode?: TimelineMode;
  initialWindowStart?: number;
  initialWindowEnd?: number;
  initialPlayheadTs?: number;
  initialProjectIds?: string[];
};

const ZOOM_OPTIONS: TimelineZoom[] = ['day', 'week', 'month', 'quarter', 'year', 'all'];

const clamp = (value: number, min: number, max: number): number => Math.min(max, Math.max(min, value));

export const TimelinePageClient = ({
  initialZoom,
  initialMode,
  initialWindowStart,
  initialWindowEnd,
  initialPlayheadTs,
  initialProjectIds
}: TimelinePageClientProps) => {
  const queryClient = useQueryClient();
  const { complete, setStatus, schedule, defer } = useItemActions();

  const now = Date.now();
  const [zoom, setZoom] = useState<TimelineZoom>(initialZoom ?? 'week');
  const [mode, setMode] = useState<TimelineMode>(initialMode ?? 'dual');
  const [windowStart, setWindowStart] = useState<number>(initialWindowStart ?? now - 3 * 24 * 60 * 60 * 1000);
  const [windowEnd, setWindowEnd] = useState<number>(initialWindowEnd ?? now + 3 * 24 * 60 * 60 * 1000);
  const [playheadTs, setPlayheadTs] = useState<number>(initialPlayheadTs ?? now);
  const [projectIds, setProjectIds] = useState<string[]>(initialProjectIds ?? []);
  const [playing, setPlaying] = useState(false);
  const [playbackSpeed, setPlaybackSpeed] = useState<1 | 2 | 4>(1);
  const [reduceMotion, setReduceMotion] = useState(false);

  const selectedItemId = useUiStore((state) => state.selectedItemId);
  const setSelectedItemId = useUiStore((state) => state.setSelectedItemId);
  const setListItemIds = useUiStore((state) => state.setListItemIds);

  useEffect(() => {
    const localSetting = window.localStorage.getItem('taskio.reduceMotion') === 'true';
    setReduceMotion(localSetting || window.matchMedia('(prefers-reduced-motion: reduce)').matches);
  }, []);

  const projectsQuery = useQuery({ queryKey: queryKeys.projects, queryFn: () => api.listProjects(false) });
  const projectIdsKey = projectIds.slice().sort().join(',');

  const timelineQuery = useQuery({
    queryKey: queryKeys.timelineView({ windowStart, windowEnd, zoom, mode, projectIds: projectIdsKey, playheadTs }),
    queryFn: () => api.getTimelineView({ windowStart, windowEnd, zoom, mode, projectIds, playheadTs })
  });

  useEffect(() => {
    if (!timelineQuery.data) return;
    const itemIds = timelineQuery.data.summary.topItems.map((item) => item.id);
    setListItemIds(itemIds);
  }, [timelineQuery.data, setListItemIds]);

  useEffect(() => {
    if (!playing || reduceMotion) return;
    const span = Math.max(1, windowEnd - windowStart);
    const step = Math.max(60_000, Math.floor((span / 100) * playbackSpeed));
    const timer = window.setInterval(() => {
      setPlayheadTs((current) => {
        const next = current + step;
        if (next > windowEnd) return windowStart;
        return next;
      });
    }, 280);
    return () => window.clearInterval(timer);
  }, [playing, playbackSpeed, reduceMotion, windowStart, windowEnd]);

  const selectedItemActionsMutation = useMutation({
    mutationFn: async (input: { tags?: string[]; link?: { url: string; label?: string } }) => {
      if (!selectedItemId) return;
      if (input.tags && input.tags.length > 0) {
        await api.updateTags(selectedItemId, input.tags);
      }
      if (input.link) {
        await api.addLink(selectedItemId, { url: input.link.url, label: input.link.label, kind: 'generic' });
      }
    },
    onSuccess: async () => {
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeys.timeline }),
        queryClient.invalidateQueries({ queryKey: queryKeys.today }),
        queryClient.invalidateQueries({ queryKey: queryKeys.upcoming }),
        queryClient.invalidateQueries({ queryKey: queryKeys.inbox }),
        queryClient.invalidateQueries({ queryKey: queryKeys.history }),
        queryClient.invalidateQueries({ queryKey: queryKeys.items })
      ]);
      if (selectedItemId) {
        await queryClient.invalidateQueries({ queryKey: queryKeys.itemDetail(selectedItemId) });
      }
    }
  });

  const visibleLaneKeys = useMemo(() => {
    if (mode === 'plan') return new Set(['plan', 'overduePressure', 'interruptions']);
    if (mode === 'reality') return new Set(['reality', 'overduePressure', 'interruptions']);
    return new Set(['plan', 'reality', 'overduePressure', 'interruptions']);
  }, [mode]);

  if (timelineQuery.isLoading) return <div className="text-sm text-muted">Loading timeline…</div>;
  if (timelineQuery.isError || !timelineQuery.data) return <div className="text-sm text-danger">Failed to load timeline.</div>;

  const timeline = timelineQuery.data;
  const laneBuckets = timeline.lanes[0]?.buckets ?? [];

  return (
    <div className="space-y-4">
      <header className="space-y-2 rounded-xl border border-stone-300 bg-panel p-3">
        <h1 className="text-2xl font-semibold text-ink">Timeline</h1>
        <p className="text-sm text-muted">Scrub work like a movie: plan, reality, interruptions, and risk over time.</p>

        <div className="flex flex-wrap items-center gap-2">
          <label className="text-xs text-muted">
            Mode
            <select
              className="ml-1 rounded border border-stone-300 bg-white px-2 py-1 text-xs"
              value={mode}
              onChange={(event) => setMode(event.target.value as TimelineMode)}
            >
              <option value="dual">Dual</option>
              <option value="plan">Plan</option>
              <option value="reality">Reality</option>
            </select>
          </label>

          <div className="flex flex-wrap gap-1">
            {ZOOM_OPTIONS.map((option) => (
              <button
                key={option}
                type="button"
                className={`rounded border px-2 py-1 text-xs ${zoom === option ? 'border-accent bg-accent/15 text-accent' : 'border-stone-300'}`}
                onClick={() => setZoom(option)}
              >
                {option}
              </button>
            ))}
          </div>

          <label className="text-xs text-muted">
            Scope
            <select
              className="ml-1 rounded border border-stone-300 bg-white px-2 py-1 text-xs"
              value={projectIdsKey}
              onChange={(event) => {
                const value = event.target.value;
                if (!value) setProjectIds([]);
                else setProjectIds(value.split(','));
              }}
            >
              <option value="">All active projects</option>
              {(projectsQuery.data ?? []).map((project) => (
                <option key={project.id} value={project.id}>
                  {project.title}
                </option>
              ))}
            </select>
          </label>

          <button type="button" className="rounded border border-stone-300 px-2 py-1 text-xs" onClick={() => setPlayheadTs(Date.now())}>
            Now
          </button>
        </div>

        <div className="flex flex-wrap items-center gap-2">
          <button
            type="button"
            className="rounded border border-stone-300 px-2 py-1 text-xs"
            onClick={() => setPlaying((value) => !value)}
            disabled={reduceMotion}
          >
            {playing ? 'Pause' : 'Play'}
          </button>
          <label className="text-xs text-muted">
            Speed
            <select
              className="ml-1 rounded border border-stone-300 bg-white px-2 py-1 text-xs"
              value={String(playbackSpeed)}
              onChange={(event) => setPlaybackSpeed(Number(event.target.value) as 1 | 2 | 4)}
            >
              <option value="1">1x</option>
              <option value="2">2x</option>
              <option value="4">4x</option>
            </select>
          </label>
          {reduceMotion ? <span className="text-xs text-muted">Playback disabled by reduced-motion preference.</span> : null}
        </div>

        <input
          type="range"
          min={windowStart}
          max={windowEnd}
          value={clamp(playheadTs, windowStart, windowEnd)}
          onChange={(event) => setPlayheadTs(Number(event.target.value))}
          className="w-full"
          aria-label="Timeline playhead scrubber"
        />
        <div className="text-xs text-muted">
          Window {new Date(windowStart).toLocaleString()} - {new Date(windowEnd).toLocaleString()} · Playhead{' '}
          {new Date(playheadTs).toLocaleString()}
        </div>
      </header>

      <section className="space-y-3 rounded-xl border border-stone-300 bg-panel p-3">
        {timeline.lanes
          .filter((lane) => visibleLaneKeys.has(lane.key))
          .map((lane) => (
            <div key={lane.key} className="space-y-1">
              <div className="text-xs font-semibold uppercase tracking-wide text-muted">{lane.label}</div>
              <div
                className="grid gap-1"
                style={{
                  gridTemplateColumns: `repeat(${Math.max(1, lane.buckets.length)}, minmax(0, 1fr))`
                }}
              >
                {lane.buckets.map((bucket, index) => {
                  const isPlayhead = playheadTs >= bucket.start && playheadTs < bucket.end;
                  const barHeight = Math.max(14, Math.min(76, 14 + bucket.count * 7));
                  return (
                    <button
                      key={`${lane.key}-${index}`}
                      type="button"
                      className={`flex items-end justify-center rounded border text-[10px] ${
                        isPlayhead ? 'border-accent bg-accent/20 text-accent' : 'border-stone-300 bg-white text-muted'
                      }`}
                      style={{ height: `${barHeight}px` }}
                      onClick={() => setPlayheadTs(Math.floor((bucket.start + bucket.end) / 2))}
                      title={`${lane.label}: ${bucket.count} in ${bucket.label}`}
                    >
                      {bucket.count}
                    </button>
                  );
                })}
              </div>
            </div>
          ))}

        <div
          className="grid gap-1 text-[10px] text-muted"
          style={{
            gridTemplateColumns: `repeat(${Math.max(1, laneBuckets.length)}, minmax(0, 1fr))`
          }}
        >
          {laneBuckets.map((bucket, index) => (
            <div key={`axis-${index}`} className="truncate text-center">
              {bucket.label}
            </div>
          ))}
        </div>
      </section>

      <section className="grid gap-4 xl:grid-cols-[2fr_1fr]">
        <div className="space-y-3 rounded-xl border border-stone-300 bg-panel p-3">
          <h2 className="text-sm font-semibold uppercase tracking-wide text-muted">What Matters</h2>
          <div className="flex flex-wrap gap-2 text-xs text-muted">
            <span className="rounded bg-stone-200 px-2 py-0.5">Plan {timeline.summary.counts.plan}</span>
            <span className="rounded bg-stone-200 px-2 py-0.5">Reality {timeline.summary.counts.reality}</span>
            <span className="rounded bg-stone-200 px-2 py-0.5">Overdue {timeline.summary.counts.overdue}</span>
            <span className="rounded bg-stone-200 px-2 py-0.5">Interruptions {timeline.summary.counts.interruptions}</span>
            <span className="rounded bg-stone-200 px-2 py-0.5">{timeline.summary.playheadLabel}</span>
          </div>

          <ItemList
            items={timeline.summary.topItems}
            selectedItemId={selectedItemId}
            onSelect={setSelectedItemId}
            emptyLabel="No top items at this playhead."
            actions={{
              onComplete: (itemId) => complete(itemId),
              onActivate: (itemId) => setStatus(itemId, 'active'),
              onInbox: (itemId) => setStatus(itemId, 'inbox'),
              onScheduleTomorrow: (itemId) => schedule(itemId, playheadTs),
              onDeferDay: (itemId) => defer(itemId, playheadTs + 24 * 60 * 60 * 1000)
            }}
          />

          <div className="flex flex-wrap gap-2">
            <button
              type="button"
              className="rounded border border-stone-300 px-2 py-1 text-xs"
              disabled={!selectedItemId}
              onClick={() => {
                if (!selectedItemId) return;
                setStatus(selectedItemId, 'canceled');
              }}
            >
              Cancel Selected
            </button>
            <button
              type="button"
              className="rounded border border-stone-300 px-2 py-1 text-xs"
              disabled={!selectedItemId}
              onClick={() => {
                if (!selectedItemId) return;
                const raw = window.prompt('Add tags (comma-separated)');
                if (!raw) return;
                const tags = raw
                  .split(',')
                  .map((value) => value.trim())
                  .filter(Boolean);
                if (tags.length > 0) selectedItemActionsMutation.mutate({ tags });
              }}
            >
              Add Tags
            </button>
            <button
              type="button"
              className="rounded border border-stone-300 px-2 py-1 text-xs"
              disabled={!selectedItemId}
              onClick={() => {
                if (!selectedItemId) return;
                const url = window.prompt('Link URL');
                if (!url) return;
                const label = window.prompt('Label (optional)') ?? undefined;
                selectedItemActionsMutation.mutate({ link: { url, label } });
              }}
            >
              Add Link
            </button>
          </div>
        </div>

        <aside className="space-y-3 rounded-xl border border-stone-300 bg-panel p-3">
          <h2 className="text-sm font-semibold uppercase tracking-wide text-muted">Timeline Moments</h2>
          <div className="space-y-2 text-xs">
            {timeline.moments.slice(0, 12).map((moment, index) => (
              <button
                key={`${moment.kind}-${moment.ts}-${index}`}
                type="button"
                className="w-full rounded border border-stone-300 bg-white px-2 py-1 text-left hover:border-accent"
                onClick={() => setPlayheadTs(moment.ts)}
              >
                <div className="font-medium text-ink">{moment.label}</div>
                <div className="text-muted">
                  {moment.kind} · count {moment.count}
                </div>
              </button>
            ))}
          </div>

          <h3 className="text-xs font-semibold uppercase tracking-wide text-muted">Recent Events @ Playhead</h3>
          <div className="space-y-1 text-xs text-muted">
            {timeline.summary.recentEvents.length === 0 ? <div>No events in this slice.</div> : null}
            {timeline.summary.recentEvents.map((event) => (
              <div key={event.id} className="rounded border border-stone-200 bg-white p-2">
                <div className="font-medium text-ink">{event.eventType}</div>
                <div>{new Date(event.occurredAt).toLocaleString()}</div>
              </div>
            ))}
          </div>
        </aside>
      </section>

      <section className="rounded-xl border border-stone-300 bg-panel p-3 text-xs text-muted">
        <div className="mb-1 font-semibold uppercase tracking-wide">Timeline Window</div>
        <div className="flex flex-wrap gap-2">
          <button type="button" className="rounded border border-stone-300 px-2 py-1" onClick={() => {
            const center = playheadTs;
            setWindowStart(center - 3 * 24 * 60 * 60 * 1000);
            setWindowEnd(center + 3 * 24 * 60 * 60 * 1000);
          }}>
            Center 1 Week
          </button>
          <button type="button" className="rounded border border-stone-300 px-2 py-1" onClick={() => {
            const center = playheadTs;
            setWindowStart(center - 15 * 24 * 60 * 60 * 1000);
            setWindowEnd(center + 15 * 24 * 60 * 60 * 1000);
          }}>
            Center 1 Month
          </button>
          <button type="button" className="rounded border border-stone-300 px-2 py-1" onClick={() => {
            setWindowStart(Date.now() - 3 * 24 * 60 * 60 * 1000);
            setWindowEnd(Date.now() + 3 * 24 * 60 * 60 * 1000);
            setPlayheadTs(Date.now());
          }}>
            Reset Default
          </button>
        </div>
      </section>
    </div>
  );
};
